catalog_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading || newValue == '') {
        return;
    }
    // Clear any previous error messages
    g_form.clearMessages();

    // 1. Parse the newly selected Start Date
    var startString = newValue.split(' ')[0]; 
    var startParts = startString.split('-');
    var startYear = parseInt(startParts[0], 10);
    var startMonth = parseInt(startParts[1], 10) - 1; 
    var startDay = parseInt(startParts[2], 10);
    var selectedStartDate = new Date(startYear, startMonth, startDay);

    // 2. Get today's date at midnight
    var today = new Date();
    today.setHours(0, 0, 0, 0);

    // 3. Check if Start Date is strictly ahead of Today
    if (selectedStartDate <= today) { 
        g_form.addErrorMessage('The Start Date must be in the future. Please select a valid date.');
        g_form.clearValue('start_date'); 
        return; // Stop running the rest of the script
    }

    // 4. Validate against End Date (if the user already filled it in)
    var endDateValue = g_form.getValue('end_date'); 
    if (endDateValue != '') {
        var endString = endDateValue.split(' ')[0];
        var endParts = endString.split('-');
        var selectedEndDate = new Date(parseInt(endParts[0], 10), parseInt(endParts[1], 10) - 1, parseInt(endParts[2], 10));

        if (selectedStartDate >= selectedEndDate) {
            g_form.addErrorMessage('The Start Date cannot be after or on the same day as the End Date.');
            g_form.clearValue('start_date');
        }
    }
}
